#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=1e5+5;
int son[maxn*32][2],idx,d[maxn],ans;
vector<pair<int,int>> g[maxn];
void dfs(int u,int f,int v){
	d[u]=v;
	for(auto p:g[u]){
		if(p.first!=f){
			dfs(p.first,u,v^p.second);
		}
	}
}
void insert(int x) {
	int p=0;
	for(int i=30; i>=0; i--) {
		int u=x>>i&1;
		if(!son[p][u]) {
			son[p][u]=++idx;
		}
		p=son[p][u];
	}
}
int query(int x) {
	int p=0,ans=0;
	for(int i=30; i>=0; i--) {
		int u=x>>i&1;
		if(son[p][u^1]) {
			p=son[p][u^1];
			ans|=1<<i;
		} else{
			p=son[p][u];
		}
	}
	return ans;
}
void clear() {
	for(int i=0; i<=idx; i++) {
		for(int j=0; j<2; j++) {
			son[i][j]=0;
		}
	}
	idx=0;
}
int n;
signed main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<n;i++){
		int u,v,w;
		cin>>u>>v>>w;
		g[u].emplace_back(v,w);
		g[v].emplace_back(u,w);
	}
	dfs(1,0,0);
	for(int i=1;i<=n;i++){
		insert(d[i]);
	}
	for(int i=1;i<=n;i++){
		ans=max(ans,query(d[i]));
	}
	cout<<ans;
	return 0;
}
